const body = ($('Receive Submission').first().json.body) || {};
const items = $('Format for Marketing').all();
const jsearchJson = $('JSearch- Fetch Job Postings').first().json;
const nextCursor = jsearchJson && jsearchJson.data && jsearchJson.data.cursor;

const esc = (v) => String(v == null ? '' : v).replace(/[&<>]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]));

let excelBase64 = '';
if (items.length > 0) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  excelBase64 = buffer.toString('base64');
}

const batchNumber = parseInt(body.page_display, 10) || 1;
const numPages = parseInt(body.num_pages, 10) || 1;
const searchLabel = body.city ? (body.job_title + ' in ' + body.city) : body.job_title;

const carryFields = ['job_title','city','country','language','date_posted','work_from_home','employment_types','job_requirements','radius'];

function hiddenInputs() {
  let out = '';
  for (const f of carryFields) {
    const v = body[f];
    if (v !== undefined && v !== null && v !== '') {
      out += '<input type="hidden" name="' + f + '" value="' + esc(v) + '">';
    }
  }
  out += '<input type="hidden" name="num_pages" value="' + esc(numPages) + '">';
  out += '<input type="hidden" name="cursor" value="' + esc(nextCursor || '') + '">';
  out += '<input type="hidden" name="page_display" value="' + esc(batchNumber + 1) + '">';
  return out;
}

const columnLabels = ['Job Title', 'Company', 'Location', 'Type', 'Posted', 'Salary'];
const headerHtml = columnLabels.map((label, i) => '<th data-col="' + i + '" onclick="sortTable(' + i + ')">' + label + '<span class="sort-indicator"></span></th>').join('') + '<th>Apply</th>';

const rowsHtml = items.map(item => {
  const j = item.json;
  return '<tr>' +
    '<td>' + esc(j['Job Title']) + '</td>' +
    '<td>' + esc(j['Company']) + '</td>' +
    '<td>' + esc(j['Location']) + '</td>' +
    '<td><span class="badge">' + esc(j['Employment Type']) + '</span></td>' +
    '<td>' + esc(j['Posted Date']) + '</td>' +
    '<td>' + esc(j['Salary']) + '</td>' +
    '<td><a href="' + esc(j['Apply Link']) + '" target="_blank" rel="noopener">Apply</a></td>' +
  '</tr>';
}).join('');

const exportBtn = items.length === 0 ? '' :
  '<a class="secondary export-btn" download="job_postings.xlsx" href="data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64,' + excelBase64 + '">Export all ' + items.length + ' to Excel</a>';

const paginationBar = items.length === 0 ? '' :
  '<div class="pagination-bar">' +
    '<span id="totalResultsLabel"></span>' +
    '<div class="page-nav">' +
      '<button type="button" id="prevPageBtn" onclick="prevPage()">&larr; Prev</button>' +
      '<span id="pageInfo"></span>' +
      '<button type="button" id="nextPageBtn" onclick="nextPage()">Next &rarr;</button>' +
      '<label>Go to page <input type="number" id="gotoPageInput" min="1" onkeyup="if(event.key===\'Enter\')gotoPage()"></label>' +
      '<button type="button" onclick="gotoPage()">Go</button>' +
    '</div>' +
  '</div>';

const tableHtml = items.length === 0
  ? '<p>No job postings found for that search. Try a different keyword.</p>'
  : '<div class="toolbar"><input type="text" id="filterInput" placeholder="Filter results..." onkeyup="filterTable()">' + exportBtn + '</div>' +
    paginationBar +
    '<table id="resultsTable"><thead><tr>' + headerHtml + '</tr></thead><tbody>' + rowsHtml + '</tbody></table>';

const loadMoreHtml = !nextCursor ? '' :
  '<div class="load-more">' +
    '<p class="hint">Loaded ' + items.length + ' results from JSearch so far (batch ' + batchNumber + ').</p>' +
    '<form method="POST" action="/webhook/job-search">' + hiddenInputs() +
      '<button type="submit" class="secondary">Fetch Next Batch from JSearch &rarr;</button>' +
    '</form>' +
  '</div>';

const css = `
:root{--accent:#2563eb;--accent-dark:#1e4fca;--border:#e2e2e2;--bg:#f7f8fa;--text:#1f2430;--muted:#6b7280;}
*{box-sizing:border-box;}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;margin:0;background:var(--bg);color:var(--text);}
.container{max-width:1000px;margin:40px auto;padding:0 20px;}
h1{font-size:26px;margin-bottom:4px;}
p.hint{color:var(--muted);font-size:14px;margin-top:0;}
table{border-collapse:collapse;width:100%;font-size:13px;margin-top:10px;background:#fff;}
th,td{padding:8px 10px;border:1px solid var(--border);text-align:left;}
th{background:#f0f2f5;cursor:pointer;user-select:none;white-space:nowrap;}
th:hover{background:#e6e9ee;}
.badge{display:inline-block;padding:2px 8px;border-radius:12px;background:#e8f0fe;color:var(--accent-dark);font-size:12px;font-weight:600;}
.toolbar{display:flex;gap:10px;align-items:center;margin-top:16px;flex-wrap:wrap;}
#filterInput{max-width:280px;padding:8px 10px;border:1px solid var(--border);border-radius:6px;font-size:14px;}
.pagination-bar{display:flex;justify-content:space-between;align-items:center;margin-top:14px;flex-wrap:wrap;gap:10px;font-size:13px;color:var(--muted);}
.page-nav{display:flex;align-items:center;gap:8px;}
.page-nav label{font-weight:normal;display:inline-flex;align-items:center;gap:6px;font-size:13px;color:var(--text);}
.page-nav input[type=number]{width:60px;padding:5px 6px;margin:0;}
.page-nav button{padding:5px 12px;background:#fff;color:var(--accent);border:1px solid var(--accent);border-radius:6px;cursor:pointer;font-size:13px;font-weight:600;}
.page-nav button:disabled{opacity:.4;cursor:default;}
.load-more{margin-top:22px;padding-top:14px;border-top:1px solid var(--border);}
.secondary{display:inline-block;padding:8px 16px;background:#fff;color:var(--accent);border:1px solid var(--accent);border-radius:6px;cursor:pointer;font-size:14px;font-weight:600;text-decoration:none;}
.secondary:hover{background:#f0f6ff;}
.export-btn{margin-left:auto;}
a.back{display:inline-block;margin-top:20px;color:var(--accent);text-decoration:none;font-weight:600;}
a.back:hover{text-decoration:underline;}
`;

const script = `
<script>
var PAGE_SIZE=10;
var currentPage=1;
function getFilteredRows(){
  var filter=document.getElementById('filterInput').value.toLowerCase();
  var allRows=Array.prototype.slice.call(document.querySelectorAll('#resultsTable tbody tr'));
  return allRows.filter(function(row){ return !filter || row.textContent.toLowerCase().indexOf(filter) > -1; });
}
function renderPage(){
  var filtered=getFilteredRows();
  var totalResults=filtered.length;
  var totalPages=Math.max(1, Math.ceil(totalResults / PAGE_SIZE));
  if(currentPage>totalPages) currentPage=totalPages;
  if(currentPage<1) currentPage=1;
  var allRows=Array.prototype.slice.call(document.querySelectorAll('#resultsTable tbody tr'));
  allRows.forEach(function(row){ row.style.display='none'; });
  var start=(currentPage-1)*PAGE_SIZE;
  filtered.slice(start, start+PAGE_SIZE).forEach(function(row){ row.style.display=''; });
  document.getElementById('pageInfo').textContent='Page '+currentPage+' of '+totalPages;
  document.getElementById('totalResultsLabel').textContent=totalResults+' result'+(totalResults===1?'':'s')+' loaded';
  document.getElementById('prevPageBtn').disabled = currentPage<=1;
  document.getElementById('nextPageBtn').disabled = currentPage>=totalPages;
  var gotoInput=document.getElementById('gotoPageInput');
  gotoInput.value=currentPage;
  gotoInput.max=totalPages;
}
function filterTable(){ currentPage=1; renderPage(); }
function prevPage(){ currentPage--; renderPage(); }
function nextPage(){ currentPage++; renderPage(); }
function gotoPage(){
  var val=parseInt(document.getElementById('gotoPageInput').value, 10);
  if(!isNaN(val)){ currentPage=val; renderPage(); }
}
var sortState={};
function sortTable(colIndex){
  var table=document.getElementById('resultsTable');
  var tbody=table.querySelector('tbody');
  var rows=Array.prototype.slice.call(tbody.querySelectorAll('tr'));
  var asc = !sortState[colIndex];
  sortState={};
  sortState[colIndex]=asc;
  rows.sort(function(a,b){
    var av=a.children[colIndex].textContent.trim().toLowerCase();
    var bv=b.children[colIndex].textContent.trim().toLowerCase();
    if(av<bv) return asc?-1:1;
    if(av>bv) return asc?1:-1;
    return 0;
  });
  rows.forEach(function(row){ tbody.appendChild(row); });
  var indicators=table.querySelectorAll('.sort-indicator');
  indicators.forEach(function(s){ s.textContent=''; });
  var activeTh=table.querySelector('th[data-col="'+colIndex+'"] .sort-indicator');
  if(activeTh) activeTh.innerHTML = asc ? '&#9650;' : '&#9660;';
  renderPage();
}
if(document.getElementById('resultsTable')) renderPage();
</script>
`;

const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Job Search Results</title><style>' + css + '</style></head><body><div class="container"><h1>Job Search Results</h1><p class="hint">Results for "' + esc(searchLabel) + '"</p>' + tableHtml + loadMoreHtml + '<a class="back" href="/webhook/job-search">&larr; New search</a></div>' + script + '</body></html>';

return [{ json: { html } }];
